private void initializeScheme(String p_uriSpec)
		throws MalformedURIException {
		int uriSpecLen = p_uriSpec.length();
		int index = p_uriSpec.indexOf(':');

		if (index < 1)
			throw new MalformedURIException("No scheme found in URI.");

